+fn format_current_datetime() -> String {
+    let now = Local::now();
+    let date = format!(
+        "{}, {} {}, {}",
+        now.format("%A"),
+        now.format("%B"),
+        now.day(),
+        now.year()
+    );
+    let time = format!("{} {}", now.format("%I:%M:%S %p"), now.format("%Z"));
+    format!("{date}, {time}")
